        int width = image.getWidth();
        int height = image.getHeight();

        // Validate dimensions
        if (width < MIN_IMAGE_DIMENSION || width > MAX_IMAGE_DIMENSION ||
            height < MIN_IMAGE_DIMENSION || height > MAX_IMAGE_DIMENSION) {
            LOGGER.warning("Invalid image dimensions: " + width + "x" + height);
            return false;
        }

        LOGGER.info("Image processed successfully: " + width + "x" + height);
        return true;
    }

    /**
