     *
     * @param contentType the content type to validate
     * @return true if the content type is a valid image format, false otherwise
     */
    private boolean isValidImageContentType(String contentType) {
        if (contentType == null || contentType.isEmpty()) {
            return true; // Allow if content type is not specified
